const Landing = () => {
  // const theme = useMantineTheme();
  const [result, setResult] = useState("");

  const handleQuotes = () => {};

  const handleSubmit = (e) => {
    e.preventDefault();
    if (
      e.target.dates != "" &&
      e.target.age.value != "" &&
      e.target.destination.value != "" &&
      e.target.activity.value != "" &&
      e.target.altitude != ""
    ) {
      setResult(
        <FaSpinner
          style={{
            animation: "spin 1s infinite linear",
          }}
        />
      );
      if (!process.env.NODE_ENV || process.env.NODE_ENV === "development") {
        var preurl = "http://localhost:8080/quotes";
      } else {
        var preurl = "https://cai-be.herokuapp.com/quotes";
      }
      fetch(
        preurl +
          `?=${encodeURIComponent(
            e.target.resident_country.value
          )}&start_date=${encodeURIComponent(
            new Date(e.target.dates.value.split("–")[0])
              .toLocaleDateString("en-ZA")
              .replaceAll("/", "-")
          )}&end_date=${encodeURIComponent(
            new Date(e.target.dates.value.split("–")[1])
              .toLocaleDateString("en-ZA")
              .replaceAll("/", "-")
          )}&age=${encodeURIComponent(
            e.target.age.value
          )}&destination=${encodeURIComponent(
            e.target.destination.value
          )}&activity=${encodeURIComponent(
            e.target.activity.value
          )}&altitude=${encodeURIComponent(
            e.target.altitude.value
          )}&guide=${encodeURIComponent(e.target.guide_required.value)}`,
        {
          method: "GET",
        }
      )
        .then((r) =>
          r.json().then((data) => ({ status: r.status, body: data }))
        )
        .then((obj) => {
          console.log(obj);
          listQuotes(obj.body.quotes);
        });
    } else {
      alert("Enter all details");
    }
  };

  const listQuotes = (list) => {
    const listItems = list.map((quote) => (
      <Card
        shadow="sm"
        p="lg"
        radius="md"
        withBorder
        style={{ height: 150, width: 800, marginBottom: 15 }}
      >
        <Flex
          gap="md"
          justify="left"
          align="flex-start"
          direction="row"
          wrap="wrap"
        >
          <Image
            src={logos[quote.provider]}
            width={150}
            height={150}
            fit="contain"
            style={{
              marginLeft: -20,
              marginTop: -20,
              marginBottom: -20,
              background: "lightcoral",
            }}
          />
          <Title order={5} style={{ maxWidth: 400, textAlign: "left" }}>
            {quote.description}
          </Title>
          <Stack
            justify="center"
            height="110px"
            style={{ gap: 0, marginLeft: "auto" }}
          >
            <Text fz="md">Premium:</Text>
            <Text fw={700} style={{ fontSize: 30 }}>
              €{quote.premium}
            </Text>
            <Button color="red" variant="filled" radius="md" size="sm">
              Get Deal
            </Button>
          </Stack>
        </Flex>
      </Card>
    ));
    setResult(listItems);
  };

  return (
    <section id="about">
      <Container fluid>
        <div className="about-content">
          <div style={{ marginBottom: 15 }}>
            <Center>
              <Group>
                <svg xmlns="http://www.w3.org/2000/svg" height="48" width="48">
                  <path d="m2 36 12-16 9.75 13H40L28 17.05l-6.25 8.3-1.9-2.5L28 12l18 24Zm25.5-3ZM8 33h12l-6-8Zm0 0h12Z" />
                </svg>
                <Title
                  order={1}
                  style={{
                    letterSpacing: -1,
                    marginBottom: 15,
                  }}
                >
                  CompareAdventureInsurance
                </Title>
              </Group>
            </Center>
          </div>

          <div style={{ marginBottom: 25 }}>
            <Container style={{ maxWidth: 800, marginBottom: 15 }}>
              <form onSubmit={(e) => handleSubmit(e)}>
                <Container style={{ marginBottom: 15 }}>
                  <Flex
                    gap="md"
                    justify="center"
                    align="flex-start"
                    direction="row"
                    wrap="wrap"
                  >
                    <Select
                      name="resident_country"
                      label="What country are you resident of?:"
                      placeholder="United Kingdom"
                      searchable
                      nothingFound="No options"
                      data={countryList}
                      style={{ width: 250 }}
                    />
                    <NumberInput
                      name="age"
                      label="What age are you?"
                      placeholder="30"
                      style={{ width: 150 }}
                    />
                  </Flex>
                </Container>
                <Container style={{ marginBottom: 25 }}>
                  <Flex
                    gap="md"
                    justify="center"
                    align="flex-start"
                    direction="row"
                    wrap="wrap"
                  >
                    <Select
                      name="destination"
                      label="Where are you going?"
                      placeholder="Nepal"
                      searchable
                      nothingFound="No options"
                      data={countryList}
                      style={{ width: 250 }}
                    />
                    <DateRangePicker
                      name="dates"
                      label="When are you travelling?"
                      placeholder="Pick dates range"
                      minDate={new Date()}
                      style={{ width: 350 }}
                    />
                  </Flex>
                </Container>
                <Container style={{ marginBottom: 15 }}>
                  <Flex
                    gap="md"
                    justify="center"
                    align="flex-start"
                    direction="row"
                    wrap="wrap"
                  >
                    <Select
                      name="activity"
                      label="What activity are you doing?"
                      placeholder="Pick one"
                      searchable
                      nothingFound="No options"
                      data={["trekking"]}
                    />
                    <NumberInput
                      name="altitude"
                      label="Maximum altitude you will reach?"
                      placeholder="3000"
                    />
                    <Select
                      name="guide_required"
                      label="Will you have a guide?"
                      placeholder="Yes"
                      data={["Yes", "No"]}
                      style={{ width: 160 }}
                    />
                  </Flex>
                </Container>
                <Container>
                  <Button
                    color="red"
                    variant="filled"
                    radius="lg"
                    size="md"
                    type="submit"
                  >
                    Get Quotes
                  </Button>
                </Container>
              </form>
            </Container>
            <Container>{result}</Container>
            <Container></Container>
          </div>
        </div>
      </Container>
    </section>
  );
};

